// BTBarChart — bar chart molecule wrapping fl_chart BarChart.
//
// Example usage:
// ```dart
// // Basic — single-series bars
// BTBarChart.basic(
//   data: [BTBarData(value: 80, label: 'Jan'), BTBarData(value: 60)],
// )
//
// // Grouped — 2 series side-by-side per x position
// BTBarChart.grouped(
//   groups: [
//     BTBarGroupData(label: 'Jan', bars: [
//       BTBarItem(value: 80, color: BTChartColors.infoBold, label: 'Revenue'),
//       BTBarItem(value: 60, color: BTChartColors.info,     label: 'Cost'),
//     ]),
//   ],
// )
//
// // Stacked — segments bottom→top
// BTBarChart.stacked(
//   stackedBars: [
//     BTStackedBarData(label: 'Jan', segments: [
//       BTBarItem(value: 40, color: BTChartColors.info,    label: 'A'),
//       BTBarItem(value: 20, color: BTChartColors.success, label: 'B'),
//     ]),
//   ],
// )
// ```
//
// Figma node 3398:521 · M - BarChart

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/chart/chart.types.dart';
import 'package:btech_ui/src/components/molecules/chart/internal/chart_colors.dart';
import 'package:btech_ui/src/components/molecules/chart/internal/chart_tooltip.dart';
import 'package:fl_chart/fl_chart.dart';
import 'package:flutter/material.dart';

/// Bar chart molecule — supports basic, grouped, and stacked variants.
///
/// All visual values come from Figma node 3398:521.
/// Wrap in [BTChartCard] for header, summary row, and legend.
///
/// Bar spacing: 8px gap between bars/groups via [BarChartAlignment.center]
/// + `groupsSpace: 8`. Bar widths: 24.5px (basic/stacked), 14px per rod
/// (grouped).
///
/// Touch / drag: press or drag across bars to see a dark BTTooltip-style
/// balloon with the x-axis label and per-series legend rows. The tooltip
/// follows the finger and auto-selects arrow direction from 4 zones.
class BTBarChart extends StatefulWidget {
  // ── named constructor: basic ─────────────────────────────────────────────

  /// Single-series bar chart. Each [BTBarData] becomes one bar (24.5px wide).
  ///
  /// Bar color defaults to [BTChartColors.info] (#0ea5e9).
  const BTBarChart.basic({
    required this.data,
    this.barColor,
    this.maxY,
    this.height = 160,
    super.key,
  })  : _variant = _BTBarVariant.basic,
        groups = const [],
        stackedBars = const [];

  // ── named constructor: grouped ───────────────────────────────────────────

  /// Multi-series grouped bar chart. Each [BTBarGroupData] contains 2+ bars
  /// shown side-by-side (14px per rod, 4px barsSpace, 8px between groups).
  const BTBarChart.grouped({
    required this.groups,
    this.maxY,
    this.height = 160,
    super.key,
  })  : _variant = _BTBarVariant.grouped,
        data = const [],
        stackedBars = const [],
        barColor = null;

  // ── named constructor: stacked ───────────────────────────────────────────

  /// Stacked bar chart. Each [BTStackedBarData] renders as one bar (24.5px)
  /// with colored segments stacked bottom→top.
  const BTBarChart.stacked({
    required this.stackedBars,
    this.maxY,
    this.height = 160,
    super.key,
  })  : _variant = _BTBarVariant.stacked,
        data = const [],
        groups = const [],
        barColor = null;

  // ── fields ───────────────────────────────────────────────────────────────

  final _BTBarVariant _variant;
  final List<BTBarData> data;
  final List<BTBarGroupData> groups;
  final List<BTStackedBarData> stackedBars;
  final Color? barColor;
  final double? maxY;
  final double height;

  @override
  State<BTBarChart> createState() => _BTBarChartState();
}

class _BTBarChartState extends State<BTBarChart> {
  /// Finger position in Stack-local coordinates (from [Listener]).
  Offset? _touchPos;

  /// X-axis label for the currently touched bar group (tooltip title).
  String? _touchTitle;

  /// Per-series items for the currently touched bar group (tooltip rows).
  List<BTChartTooltipItem>? _touchItems;

  // ── build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    final effectiveBarColor = widget.barColor ?? BTChartColors.info;
    final effectiveMaxY = widget.maxY ?? _inferMaxY();

    final barGroups = switch (widget._variant) {
      _BTBarVariant.basic => _buildBasicGroups(effectiveBarColor),
      _BTBarVariant.grouped => _buildGroupedGroups(),
      _BTBarVariant.stacked => _buildStackedGroups(),
    };

    final xLabels = switch (widget._variant) {
      _BTBarVariant.basic =>
        widget.data.map((d) => d.label ?? 'Label').toList(),
      _BTBarVariant.grouped =>
        widget.groups.map((g) => g.label ?? 'Label').toList(),
      _BTBarVariant.stacked =>
        widget.stackedBars.map((b) => b.label ?? 'Label').toList(),
    };

    final axisTextStyle = TextStyle(
      fontFamily: BTTypography.fontFamily,
      fontSize: 10.0,
      fontWeight: FontWeight.w500,
      color: colors.text.secondary,
    );

    // Capture effectiveBarColor for closure — barColor is widget field.
    final capturedBarColor = effectiveBarColor;

    // fl_chart's built-in tooltip is disabled; we render our own overlay.
    final chart = BarChart(
      BarChartData(
        maxY: effectiveMaxY,
        alignment: BarChartAlignment.center,
        groupsSpace: 8,
        barGroups: barGroups,
        gridData: FlGridData(
          show: true,
          drawVerticalLine: false,
          horizontalInterval: effectiveMaxY / 5,
          getDrawingHorizontalLine: (_) => FlLine(
            color: colors.border.primary,
            strokeWidth: 1,
          ),
        ),
        borderData: FlBorderData(show: false),
        titlesData: FlTitlesData(
          leftTitles: AxisTitles(
            sideTitles: SideTitles(
              showTitles: true,
              reservedSize: 28,
              interval: effectiveMaxY / 5,
              getTitlesWidget: (value, _) => Text(
                value.toInt().toString(),
                style: axisTextStyle,
                textAlign: TextAlign.end,
              ),
            ),
          ),
          bottomTitles: AxisTitles(
            sideTitles: SideTitles(
              showTitles: true,
              reservedSize: 20,
              getTitlesWidget: (value, _) {
                final idx = value.toInt();
                final label = (idx >= 0 && idx < xLabels.length)
                    ? xLabels[idx]
                    : '';
                return Padding(
                  padding: EdgeInsetsDirectional.only(top: 4.0),
                  child: Text(label, style: axisTextStyle),
                );
              },
            ),
          ),
          rightTitles: const AxisTitles(
            sideTitles: SideTitles(showTitles: false),
          ),
          topTitles: const AxisTitles(
            sideTitles: SideTitles(showTitles: false),
          ),
        ),
        barTouchData: BarTouchData(
          handleBuiltInTouches: false,
          touchCallback: (FlTouchEvent event, BarTouchResponse? response) {
            if (!mounted) return;
            if (!event.isInterestedForInteractions ||
                response == null ||
                response.spot == null) {
              if (_touchItems != null) {
                setState(() {
                  _touchTitle = null;
                  _touchItems = null;
                });
              }
              return;
            }

            final spot = response.spot!;
            final groupIdx = spot.touchedBarGroupIndex;

            // ── Build tooltip title from x-axis label ──────────────────
            final newTitle = switch (widget._variant) {
              _BTBarVariant.basic =>
                (groupIdx >= 0 && groupIdx < widget.data.length)
                    ? widget.data[groupIdx].label ?? 'Label'
                    : 'Label',
              _BTBarVariant.grouped =>
                (groupIdx >= 0 && groupIdx < widget.groups.length)
                    ? widget.groups[groupIdx].label ?? 'Label'
                    : 'Label',
              _BTBarVariant.stacked =>
                (groupIdx >= 0 && groupIdx < widget.stackedBars.length)
                    ? widget.stackedBars[groupIdx].label ?? 'Label'
                    : 'Label',
            };

            // ── Build tooltip item rows from touched group ─────────────
            final newItems = switch (widget._variant) {
              // Basic: single item, no series label
              _BTBarVariant.basic => <BTChartTooltipItem>[
                  BTChartTooltipItem(
                    color: capturedBarColor,
                    label: '',
                    value: spot.touchedRodData.toY.toStringAsFixed(0),
                  ),
                ],

              // Grouped: one item per rod in the touched group
              _BTBarVariant.grouped =>
                (groupIdx >= 0 && groupIdx < widget.groups.length)
                    ? widget.groups[groupIdx].bars
                        .asMap()
                        .entries
                        .map((e) {
                          // Use all rods from the group for full picture
                          final rodY =
                              spot.touchedBarGroup.barRods.length > e.key
                                  ? spot.touchedBarGroup.barRods[e.key].toY
                                  : e.value.value;
                          return BTChartTooltipItem(
                            color: e.value.color,
                            label: e.value.label ?? '',
                            value: rodY.toStringAsFixed(0),
                          );
                        })
                        .toList()
                    : <BTChartTooltipItem>[],

              // Stacked: one item per segment at touched x
              _BTBarVariant.stacked =>
                (groupIdx >= 0 && groupIdx < widget.stackedBars.length)
                    ? widget.stackedBars[groupIdx].segments
                        .map(
                          (seg) => BTChartTooltipItem(
                            color: seg.color,
                            label: seg.label ?? '',
                            value: seg.value.toStringAsFixed(0),
                          ),
                        )
                        .toList()
                    : <BTChartTooltipItem>[],
            };

            if (_touchTitle != newTitle || _touchItems != newItems) {
              setState(() {
                _touchTitle = newTitle;
                _touchItems = newItems;
              });
            }
          },
        ),
      ),
    );

    return SizedBox(
      height: widget.height,
      child: LayoutBuilder(
        builder: (context, constraints) {
          final chartWidth = constraints.maxWidth;
          return Stack(
            clipBehavior: Clip.none,
            children: [
              Listener(
                onPointerDown: (e) =>
                    setState(() => _touchPos = e.localPosition),
                onPointerMove: (e) {
                  final pos = e.localPosition;
                  if (pos.dx < 0 ||
                      pos.dx > chartWidth ||
                      pos.dy < 0 ||
                      pos.dy > widget.height) {
                    setState(() {
                      _touchPos = null;
                      _touchTitle = null;
                      _touchItems = null;
                    });
                  } else {
                    setState(() => _touchPos = pos);
                  }
                },
                onPointerUp: (_) => setState(() {
                  _touchPos = null;
                  _touchTitle = null;
                  _touchItems = null;
                }),
                onPointerCancel: (_) => setState(() {
                  _touchPos = null;
                  _touchTitle = null;
                  _touchItems = null;
                }),
                child: chart,
              ),
              if (_touchPos != null && _touchItems != null)
                BTChartTooltipOverlay(
                  title: _touchTitle,
                  items: _touchItems,
                  touchDx: _touchPos!.dx,
                  touchDy: _touchPos!.dy,
                  chartWidth: chartWidth,
                  chartHeight: widget.height,
                ),
            ],
          );
        },
      ),
    );
  }

  // ── group builders ────────────────────────────────────────────────────────

  static const BorderRadius _topRadius = BorderRadius.only(
    topLeft: Radius.circular(2),
    topRight: Radius.circular(2),
  );

  List<BarChartGroupData> _buildBasicGroups(Color color) {
    return widget.data.asMap().entries.map((e) {
      return BarChartGroupData(
        x: e.key,
        barRods: [
          BarChartRodData(
            toY: e.value.value,
            color: color,
            width: 24.5,
            borderRadius: _topRadius,
          ),
        ],
      );
    }).toList();
  }

  List<BarChartGroupData> _buildGroupedGroups() {
    return widget.groups.asMap().entries.map((e) {
      return BarChartGroupData(
        x: e.key,
        barsSpace: 4,
        barRods: e.value.bars.map((b) {
          return BarChartRodData(
            toY: b.value,
            color: b.color,
            width: 14,
            borderRadius: _topRadius,
          );
        }).toList(),
      );
    }).toList();
  }

  List<BarChartGroupData> _buildStackedGroups() {
    return widget.stackedBars.asMap().entries.map((e) {
      final bar = e.value;
      final total =
          bar.segments.fold<double>(0, (sum, s) => sum + s.value);
      var runningY = 0.0;
      final rodItems = bar.segments.map((s) {
        final item =
            BarChartRodStackItem(runningY, runningY + s.value, s.color);
        runningY += s.value;
        return item;
      }).toList();

      return BarChartGroupData(
        x: e.key,
        barRods: [
          BarChartRodData(
            toY: total,
            rodStackItems: rodItems,
            width: 24.5,
            borderRadius: _topRadius,
            color: Colors.transparent,
          ),
        ],
      );
    }).toList();
  }

  // ── helpers ───────────────────────────────────────────────────────────────

  double _inferMaxY() {
    var max = 0.0;
    switch (widget._variant) {
      case _BTBarVariant.basic:
        for (final d in widget.data) {
          if (d.value > max) max = d.value;
        }
      case _BTBarVariant.grouped:
        for (final g in widget.groups) {
          for (final b in g.bars) {
            if (b.value > max) max = b.value;
          }
        }
      case _BTBarVariant.stacked:
        for (final bar in widget.stackedBars) {
          final total =
              bar.segments.fold<double>(0, (s, seg) => s + seg.value);
          if (total > max) max = total;
        }
    }
    if (max == 0) return 100;
    return ((max / 20).ceil() * 20).toDouble();
  }
}

enum _BTBarVariant { basic, grouped, stacked }

// Chart molecule family barrel.
//
// Exports: BTBarChart, BTLineChart, BTCircleChart, all data models,
// and BTChartColors palette for seeding chart data.
// Internal layout helpers (BTChartLegend) are NOT re-exported.
export 'package:btech_ui/src/components/molecules/chart/bar_chart.widget.dart';
export 'package:btech_ui/src/components/molecules/chart/chart.types.dart';
export 'package:btech_ui/src/components/molecules/chart/circle_chart.widget.dart';
export 'package:btech_ui/src/components/molecules/chart/internal/chart_colors.dart';
export 'package:btech_ui/src/components/molecules/chart/line_chart.widget.dart';

// BTChart data models — shared across all chart widget types.
//
// Consumers build their data with these plain classes and pass them
// to BTBarChart / BTLineChart / BTCircleChart / BTChartCard.
// fl_chart types are never exposed publicly.

import 'package:flutter/painting.dart';

// ── Bar Chart ──────────────────────────────────────────────────────────────

/// A single data point for [BTBarChart.basic].
class BTBarData {
  const BTBarData({
    required this.value,
    this.label,
  });

  /// X-axis label shown below the bar. Defaults to 'Label' if null.
  final String? label;

  /// Bar height value.
  final double value;
}

/// One bar in a grouped [BTBarChart.grouped] group, or one segment in a
/// stacked [BTBarChart.stacked] bar.
class BTBarItem {
  const BTBarItem({
    required this.value,
    required this.color,
    this.label,
  });

  final double value;
  final Color color;

  /// Optional series name shown in the tooltip legend row.
  final String? label;
}

/// A group of bars in [BTBarChart.grouped] (shown side-by-side).
class BTBarGroupData {
  const BTBarGroupData({
    required this.bars,
    this.label,
  });

  /// X-axis label for this group.
  final String? label;

  /// The individual bars in this group (≥1). Each has a value + color.
  final List<BTBarItem> bars;
}

/// One position in [BTBarChart.stacked] (multiple stacked segments).
class BTStackedBarData {
  const BTStackedBarData({
    required this.segments,
    this.label,
  });

  /// X-axis label.
  final String? label;

  /// Segments bottom→top. Each has a value + color.
  final List<BTBarItem> segments;
}

// ── Line Chart ─────────────────────────────────────────────────────────────

/// One (x, y) coordinate in a line chart series.
class BTLineSpot {
  const BTLineSpot(this.x, this.y);

  final double x;
  final double y;
}

/// A single line series in [BTLineChart].
class BTLineSeries {
  const BTLineSeries({
    required this.spots,
    required this.color,
    this.label,
  });

  /// Legend label for this series.
  final String? label;

  /// Ordered list of (x, y) data points.
  final List<BTLineSpot> spots;

  /// Line and fill color.
  final Color color;
}

// ── Circle Chart ───────────────────────────────────────────────────────────

/// One slice in [BTCircleChart].
class BTCircleSection {
  const BTCircleSection({
    required this.value,
    required this.color,
    this.label,
  });

  /// Label shown outside the circle near this slice.
  final String? label;

  /// Proportional value (raw — the widget computes percentages internally).
  final double value;

  final Color color;
}

// ── Tooltip ────────────────────────────────────────────────────────────────

/// One row in a [BTChartTooltipOverlay] balloon.
///
/// Each item renders as:
///   [12×12 color square]  [label, flex-1]  [value, bold]
class BTChartTooltipItem {
  const BTChartTooltipItem({
    required this.color,
    required this.label,
    required this.value,
  });

  /// Legend color swatch (12×12, borderRadius 2).
  final Color color;

  /// Series name — pass empty string to hide label column.
  final String label;

  /// Formatted value string (e.g. '42', '38%').
  final String value;
}

// ── Chart Card ─────────────────────────────────────────────────────────────

/// One item in the summary row of [BTChartCard].
class BTChartSummaryItem {
  const BTChartSummaryItem({
    required this.label,
    required this.value,
    this.unit,
  });

  /// Small label above the value (e.g. 'Total Sales').
  final String label;

  /// Bold value (e.g. '1,200').
  final String value;

  /// Optional unit suffix in small text (e.g. '%', 'kg').
  final String? unit;
}

/// One item in the legend row of [BTChartCard].
class BTChartLegendItem {
  const BTChartLegendItem({
    required this.label,
    required this.color,
  });

  final String label;
  final Color color;
}

// BTCircleChart — pie / donut / donut-rounded chart molecule.
//
// Example usage:
// ```dart
// // Pie
// BTCircleChart.pie(
//   sections: [
//     BTCircleSection(value: 40, color: BTChartColors.info, label: 'A'),
//     BTCircleSection(value: 60, color: BTChartColors.success, label: 'B'),
//   ],
// )
//
// // Donut (large center hole)
// BTCircleChart.donut(sections: [...])
//
// // Donut with gaps + rounded ends
// BTCircleChart.donutRounded(sections: [...])
// ```
//
// Figma node 3404:1813 · M - CircleChart

// ignore_for_file: lines_longer_than_80_chars

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/chart/chart.types.dart';
import 'package:btech_ui/src/components/molecules/chart/internal/chart_tooltip.dart';
import 'package:btech_ui/src/components/molecules/chart/internal/circle_chart_labels.dart';
import 'package:btech_ui/src/components/molecules/chart/internal/circle_chart_painter.dart';
import 'package:fl_chart/fl_chart.dart';
import 'package:flutter/material.dart';

/// Circle chart molecule — pie, donut, and gapped-donut variants.
///
/// All visual values come from Figma node 3404:1813.
/// Every variant shows external badge labels (Label + %) connected to their
/// segment by a short radial line. Tapping a segment shows a BTTooltip-style
/// balloon overlay for all variants.
///
/// ## Radius layout (per variant, in a [size]×[size] widget)
///
/// All three variants share the same true outer radius of 70 px (default
/// [size] 178) so connector lines and badge labels align identically.
/// The difference is only in the center-hole size and ring thickness:
///
/// | Variant       | Center hole | Ring | True outer |
/// |---------------|-------------|------|-----------|
/// | pie           | 0 px        | 70   | 70        |
/// | donut         | 36 px       | 34   | 70        |
/// | donutRounded  | 40 px       | 30   | 70        |
///
/// fl_chart note: [PieChartSectionData.radius] is the **ring thickness**
/// (distance from the inner hole edge to the outer edge), NOT the outer radius.
/// The true outer radius = centerSpaceRadius + section.radius.
class BTCircleChart extends StatefulWidget {
  // ── named constructor: pie ───────────────────────────────────────────────

  /// Full pie chart (no center hole, no gaps, no rounded ends).
  const BTCircleChart.pie({
    required this.sections,
    this.size = 178,
    super.key,
  })  : _innerRadius = 0,
        _sectionsSpace = 0;

  // ── named constructor: donut ─────────────────────────────────────────────

  /// Donut chart — large center hole, no gaps, no rounded ends.
  const BTCircleChart.donut({
    required this.sections,
    this.size = 178,
    super.key,
  })  : _innerRadius = 36,
        _sectionsSpace = 0;

  // ── named constructor: donutRounded ──────────────────────────────────────

  /// Donut chart — 4 px gaps between segments, rounded ends.
  ///
  /// Visual rendering uses a [BTDonutRoundedPainter] ([StrokeCap.round]) for
  /// the colored arcs. fl_chart is used (with transparent sections) only for
  /// touch detection and badge-label positioning.
  const BTCircleChart.donutRounded({
    required this.sections,
    this.size = 178,
    super.key,
  })  : _innerRadius = 40,
        _sectionsSpace = 4;

  // ── fields ────────────────────────────────────────────────────────────────

  final List<BTCircleSection> sections;
  final double size;
  final double _innerRadius;
  final double _sectionsSpace;

  @override
  State<BTCircleChart> createState() => _BTCircleChartState();
}

class _BTCircleChartState extends State<BTCircleChart> {
  /// Index of the currently tapped section, or -1 for none.
  int _touchedIndex = -1;

  /// Touch position in local Stack coordinates — used for tooltip placement.
  Offset? _touchPos;

  // ── radius helpers ────────────────────────────────────────────────────────

  /// Ring thickness (= [PieChartSectionData.radius] in fl_chart).
  ///
  /// fl_chart draws the ring from [_innerRadius] to
  /// [_innerRadius] + [_ringThickness] — the outer edge is at
  /// [_trueOuterRadius].
  double get _ringThickness {
    if (widget._innerRadius == 0) return 70; // pie: ring = outer = 70
    if (widget._sectionsSpace > 0) return 30; // donutRounded: outer = 70
    return 34; // donut: outer = 70
  }

  /// True outer radius of the visible section edge (center hole + ring).
  /// All three variants equal 70 px at the default [size] of 178.
  double get _trueOuterRadius => widget._innerRadius + _ringThickness;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final total =
        widget.sections.fold<double>(0, (s, sec) => s + sec.value);

    final ringThickness = _ringThickness;
    final trueOuterRadius = _trueOuterRadius; // 70 px for all variants

    // Badge offset: places label 30 px beyond the section outer edge.
    // Formula derivation:
    //   badge_center = centerSpace + ringThickness × offset
    //   We want badge_center = trueOuter + 30 = centerSpace + ringThickness + 30
    //   ⟹  offset = 1 + 30 / ringThickness
    //
    // The connector line ends at trueOuter + 13 (gap 3 + length 10).
    // With two 10 px text lines (~13 px line-height each, 26 px total height),
    // badge top = trueOuter + 30 − 13 = trueOuter + 17 → 4 px gap from line tip.
    final badgeOffset = 1.0 + 30.0 / ringThickness;

    // True for both Donut and DonutRounded — colored arcs drawn by
    // BTDonutRoundedPainter; fl_chart sections become touch/badge targets only.
    final isDonutVariant = widget._innerRadius > 0;
    final isDonutRounded = widget._sectionsSpace > 0;

    final pieSections =
        widget.sections.asMap().entries.map((entry) {
      final isTouched = entry.key == _touchedIndex;
      final sec = entry.value;
      final pct = total > 0 ? sec.value / total * 100 : 0.0;

      return PieChartSectionData(
        value: sec.value,
        // Donut / DonutRounded: transparent — colored arcs drawn by
        // BTDonutRoundedPainter. Pie: use section color.
        color: isDonutVariant ? Colors.transparent : sec.color,
        // section.radius = ring thickness (NOT outer radius from center).
        radius: isTouched ? ringThickness + 8 : ringThickness,
        borderSide: const BorderSide(color: Colors.transparent, width: 0),
        showTitle: false,
        badgeWidget: BTCirclePieLabel(
          label: sec.label ?? '',
          value: '${pct.toStringAsFixed(0)}%',
          textColor: c.text.secondary,
          boldTextColor: c.text.primary,
        ),
        badgePositionPercentageOffset: badgeOffset,
      );
    }).toList();

    final chart = PieChart(
      PieChartData(
        sections: pieSections,
        centerSpaceRadius: widget._innerRadius,
        // Always 0 — for donutRounded the visual gap is drawn by
        // BTDonutRoundedPainter so fl_chart badge positions are unaffected.
        sectionsSpace: 0,
        startDegreeOffset: -90,
        pieTouchData: PieTouchData(
          touchCallback: (FlTouchEvent event, PieTouchResponse? response) {
            setState(() {
              if (!event.isInterestedForInteractions ||
                  response == null ||
                  response.touchedSection == null) {
                _touchedIndex = -1;
                _touchPos = null;
                return;
              }
              _touchedIndex =
                  response.touchedSection!.touchedSectionIndex;
            });
          },
        ),
      ),
    );

    // Tooltip value: "Label XX%" or "XX%" when label is absent.
    final section = _touchedIndex >= 0 &&
            _touchedIndex < widget.sections.length
        ? widget.sections[_touchedIndex]
        : null;
    final pct = section != null && total > 0
        ? section.value / total * 100
        : 0.0;
    final tooltipValue = section != null
        ? (section.label != null && section.label!.isNotEmpty
            ? '${section.label} ${pct.toStringAsFixed(0)}%'
            : '${pct.toStringAsFixed(0)}%')
        : null;

    return SizedBox(
      width: widget.size,
      height: widget.size,
      child: Stack(
        clipBehavior: Clip.none,
        alignment: Alignment.center,
        children: [
          // ① Radial connector lines — behind chart, non-interactive.
          //   Uses trueOuterRadius (= centerSpaceRadius + ringThickness)
          //   so lines start at the ACTUAL outer edge of the chart ring.
          IgnorePointer(
            child: CustomPaint(
              size: Size(widget.size, widget.size),
              painter: BTCircleConnectorPainter(
                sections: widget.sections,
                total: total,
                outerRadius: trueOuterRadius,
                color: c.text.secondary,
              ),
            ),
          ),

          // ② Donut + DonutRounded: colored arcs via BTDonutRoundedPainter.
          //   • Donut:        StrokeCap.butt, no gap, no border — eliminates
          //                   the sub-pixel anti-aliasing gaps fl_chart leaves
          //                   at section boundaries.
          //   • DonutRounded: StrokeCap.round, 4 px gap, 2 px white border.
          //   Drawn above connector lines but below the fl_chart badge labels.
          if (isDonutVariant)
            IgnorePointer(
              child: CustomPaint(
                size: Size(widget.size, widget.size),
                painter: BTDonutRoundedPainter(
                  sections: widget.sections,
                  total: total,
                  innerRadius: widget._innerRadius,
                  outerRadius: trueOuterRadius,
                  touchedIndex: _touchedIndex,
                  sectionsGap: widget._sectionsSpace,
                  cap: isDonutRounded ? StrokeCap.round : StrokeCap.butt,
                  borderWidth: isDonutRounded ? 2.0 : 0.0,
                  borderColor: c.bg.primary,
                ),
              ),
            ),

          // ③ Chart widget — fl_chart renders sections (transparent for
          //   donutRounded) + badge labels, and drives touch events.
          //   Listener tracks pointer position for tooltip placement.
          Listener(
            onPointerDown: (e) =>
                setState(() => _touchPos = e.localPosition),
            onPointerMove: (e) {
              final pos = e.localPosition;
              if (pos.dx < 0 ||
                  pos.dx > widget.size ||
                  pos.dy < 0 ||
                  pos.dy > widget.size) {
                setState(() {
                  _touchPos = null;
                  _touchedIndex = -1;
                });
              } else {
                setState(() => _touchPos = pos);
              }
            },
            onPointerUp: (_) => setState(() {
              _touchPos = null;
              _touchedIndex = -1;
            }),
            onPointerCancel: (_) => setState(() {
              _touchPos = null;
              _touchedIndex = -1;
            }),
            child: chart,
          ),

          // ④ Floating tooltip balloon — title-only (simple mode).
          if (_touchPos != null && tooltipValue != null)
            BTChartTooltipOverlay(
              title: tooltipValue,
              touchDx: _touchPos!.dx,
              touchDy: _touchPos!.dy,
              chartWidth: widget.size,
              chartHeight: widget.size,
            ),
        ],
      ),
    );
  }
}

