/// Internal chart tooltip overlay — dark balloon + directional arrow.
///
/// Supports two display modes:
///
/// **Simple** (circle chart): pass [title] only.
/// ```dart
/// BTChartTooltipOverlay(title: 'A 40%', touchDx: ..., ...)
/// ```
///
/// **Rich** (bar / line chart): pass [title] + [items].
/// ```dart
/// BTChartTooltipOverlay(
///   title: 'Jan',
///   items: [
///     BTChartTooltipItem(color: BTChartColors.info,    label: 'Revenue', value: '80'),
///     BTChartTooltipItem(color: BTChartColors.success, label: 'Cost',    value: '60'),
///   ],
///   touchDx: ..., touchDy: ..., chartWidth: ..., chartHeight: ...,
/// )
/// ```
///
/// Direction is chosen automatically from the touch position:
///   touchDy < 25% chart height → ABOVE (arrow at bottom, points down)
///   touchDy > 75% chart height → BELOW (arrow at top, points up)
///   middle + left half         → LEFT  (arrow at right, points right toward bar)
///   middle + right half        → RIGHT (arrow at left, points left toward bar)
class BTChartTooltipOverlay extends StatelessWidget {
  const BTChartTooltipOverlay({
    required this.touchDx,
    required this.touchDy,
    required this.chartWidth,
    required this.chartHeight,
    this.title,
    this.items,
    super.key,
  });

  /// Optional headline shown at the top of the balloon (centered).
  /// For simple tooltips (e.g. circle chart) this is the only content.
  final String? title;

  /// Optional list of legend rows shown below the separator.
  /// When non-null and non-empty, a divider is drawn between title and rows.
  final List<BTChartTooltipItem>? items;

  /// Horizontal touch position in Stack-local coordinates.
  final double touchDx;

  /// Vertical touch position in Stack-local coordinates.
  final double touchDy;

  /// Full width of the chart widget (from LayoutBuilder).
  final double chartWidth;

  /// Full height of the chart widget.
  final double chartHeight;

  // Gap between the arrow tip and the touch point (matches BTTooltip._gap).
  static const double _gap = 6;

  // Arrow short dimension: 8px (matches BTTooltipArrow's isVertical sizing).
  static const double _arrowShort = 8;

  @override
  Widget build(BuildContext context) {
    final dir = _resolveDirection();
    final c = context.btColor;
    final bg = c.bg.inverse;
    final textColor = c.text.inverse;

    final balloon = _BTChartBalloon(
      title: title,
      items: items,
      bg: bg,
      textColor: textColor,
    );

    // Reuse the same BTTooltipArrow used by BTTooltip — identical appearance.
    final arrow = BTTooltipArrow(
      direction: _btPos(dir),
      color: bg,
    );

    Widget tooltip;
    Offset translation;
    double left;
    double top;

    switch (dir) {
      // ── Balloon ABOVE touch, arrow points DOWN toward bar ─────────────────
      case _Dir.above:
        tooltip = Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [balloon, arrow],
        );
        left = touchDx;
        top = touchDy - _gap;
        translation = const Offset(-0.5, -1);

      // ── Balloon BELOW touch, arrow points UP toward touch ─────────────────
      case _Dir.below:
        tooltip = Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [arrow, balloon],
        );
        left = touchDx;
        top = touchDy + _gap;
        translation = const Offset(-0.5, 0);

      // ── Balloon to the RIGHT, arrow points LEFT toward bar ────────────────
      case _Dir.right:
        tooltip = Row(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [arrow, balloon],
        );
        left = touchDx + _gap;
        top = touchDy;
        translation = const Offset(0, -0.5);

      // ── Balloon to the LEFT, arrow points RIGHT toward bar ────────────────
      case _Dir.left:
        tooltip = Row(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [balloon, arrow],
        );
        left = touchDx - _gap - _arrowShort;
        top = touchDy;
        translation = const Offset(-1, -0.5);
    }

    return Positioned(
      left: left,
      top: top,
      child: FractionalTranslation(
        translation: translation,
        child: tooltip,
      ),
    );
  }

  _Dir _resolveDirection() {
    final relY = touchDy / chartHeight;
    if (relY < 0.25) return _Dir.above;
    if (relY > 0.75) return _Dir.below;
    return touchDx < chartWidth * 0.5 ? _Dir.left : _Dir.right;
  }

  static BTTooltipPosition _btPos(_Dir dir) => switch (dir) {
        _Dir.above => BTTooltipPosition.top,
        _Dir.below => BTTooltipPosition.bottom,
        _Dir.right => BTTooltipPosition.right,
        _Dir.left => BTTooltipPosition.left,
      };
}

enum _Dir { above, below, left, right }

