/// Draws short radial connector lines from each pie/donut segment's outer
/// edge toward its external badge label (Figma node 3404:1813).
///
/// Place this as a [CustomPaint] in a [Stack] behind the [PieChart] widget so
/// that the lines appear between the chart edge and the floating labels.
class BTCircleConnectorPainter extends CustomPainter {
  const BTCircleConnectorPainter({
    required this.sections,
    required this.total,
    required this.outerRadius,
    required this.color,
  });

  final List<BTCircleSection> sections;
  final double total;

  /// TRUE outer radius of the chart ring — i.e. centerSpaceRadius + ringThickness.
  /// For pie this equals [ringThickness]; for donut/donutRounded use
  /// [centerSpaceRadius] + [ringThickness].
  final double outerRadius;

  final Color color;

  // Gap between section outer edge and line start.
  static const double _gap = 3;
  // Length of each connector line in logical pixels.
  static const double _length = 10;

  @override
  void paint(Canvas canvas, Size size) {
    if (total <= 0) return;
    final center = Offset(size.width / 2, size.height / 2);
    final paint = Paint()
      ..color = color
      ..strokeWidth = 1.0
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.round;

    var angle = -90.0; // startDegreeOffset: -90 (12 o'clock)
    for (final sec in sections) {
      final sweep = sec.value / total * 360;
      final mid = (angle + sweep / 2) * pi / 180;
      final dir = Offset(cos(mid), sin(mid));
      canvas.drawLine(
        center + dir * (outerRadius + _gap),
        center + dir * (outerRadius + _gap + _length),
        paint,
      );
      angle += sweep;
    }
  }

  @override
  bool shouldRepaint(BTCircleConnectorPainter oldDelegate) =>
      oldDelegate.sections != sections ||
      oldDelegate.total != total ||
      oldDelegate.outerRadius != outerRadius ||
      oldDelegate.color != color;
}

/// Draws donut/donutRounded arcs using [Paint.strokeCap] so section edges
/// are rendered cleanly (no sub-pixel anti-aliasing gaps at boundaries).
///
/// Used for **both** the plain Donut variant (flat ends, no gap, no border)
/// and the DonutRounded variant (rounded ends, 4 px gap, optional border).
///
/// fl_chart is still used (with transparent sections) for badge-label
/// positioning and touch detection; this painter sits below it in the [Stack].
class BTDonutRoundedPainter extends CustomPainter {
  const BTDonutRoundedPainter({
    required this.sections,
    required this.total,
    required this.innerRadius,
    required this.outerRadius,
    required this.touchedIndex,
    this.sectionsGap = 4.0,
    this.cap = StrokeCap.round,
    this.borderWidth = 0.0,
    this.borderColor = Colors.white,
  });

  final List<BTCircleSection> sections;
  final double total;

  /// Radius of the center hole.
  final double innerRadius;

  /// True outer radius of the ring (innerRadius + ringThickness).
  final double outerRadius;

  /// Index of the currently touched segment, or -1 for none.
  final int touchedIndex;

  /// Pixel gap between segments (measured at the ring mid-radius).
  /// Use 0 for the plain Donut variant.
  final double sectionsGap;

  /// End-cap style: [StrokeCap.round] for donutRounded,
  /// [StrokeCap.butt] for plain Donut.
  final StrokeCap cap;

  /// Width of the border drawn on the inner and outer edges of each arc.
  /// 0 means no border (plain Donut). Typically 2 for donutRounded.
  final double borderWidth;

  /// Color of the border — should match the background so it creates a
  /// "knockout" outline effect.
  final Color borderColor;

  @override
  void paint(Canvas canvas, Size size) {
    if (total <= 0) return;
    final center = Offset(size.width / 2, size.height / 2);
    final baseStrokeWidth = outerRadius - innerRadius;
    final baseMidRadius = (innerRadius + outerRadius) / 2;

    // Convert pixel gap to radians at the mid-radius.
    // When sectionsGap == 0 (plain Donut), gapRadians == 0 and arcs are flush.
    final gapRadians =
        sectionsGap > 0 ? sectionsGap / baseMidRadius : 0.0;

    var startAngle = -pi / 2; // 12 o'clock (matches fl_chart startDegreeOffset)

    for (var i = 0; i < sections.length; i++) {
      final sec = sections[i];
      final sectionSweep = sec.value / total * 2 * pi;

      // Shrink sweep by one full gap (half on each side).
      final adjustedSweep = sectionSweep - gapRadians;
      if (adjustedSweep <= 0) {
        startAngle += sectionSweep;
        continue;
      }

      final isTouched = i == touchedIndex;
      // When touched, expand ring outward by 8 px (mirrors fl_chart behavior).
      final strokeWidth =
          isTouched ? baseStrokeWidth + 8 : baseStrokeWidth;
      final midRadius = isTouched ? baseMidRadius + 4 : baseMidRadius;

      final arcStart = startAngle + gapRadians / 2;
      final arcRect = Rect.fromCircle(center: center, radius: midRadius);

      // ── 1. Border pass (drawn wider, with background color) ─────────────
      // Appears as a 2 px outline on both inner and outer edges of the arc.
      if (borderWidth > 0) {
        canvas.drawArc(
          arcRect,
          arcStart,
          adjustedSweep,
          false,
          Paint()
            ..color = borderColor
            ..style = PaintingStyle.stroke
            ..strokeWidth = strokeWidth + borderWidth * 2
            ..strokeCap = cap,
        );
      }

      // ── 2. Fill pass (section color) ─────────────────────────────────────
      canvas.drawArc(
        arcRect,
        arcStart,
        adjustedSweep,
        false,
        Paint()
          ..color = sec.color
          ..style = PaintingStyle.stroke
          ..strokeWidth = strokeWidth
          ..strokeCap = cap,
      );

      startAngle += sectionSweep;
    }
  }

  @override
  bool shouldRepaint(BTDonutRoundedPainter oldDelegate) =>
      oldDelegate.sections != sections ||
      oldDelegate.total != total ||
      oldDelegate.innerRadius != innerRadius ||
      oldDelegate.outerRadius != outerRadius ||
      oldDelegate.touchedIndex != touchedIndex ||
      oldDelegate.sectionsGap != sectionsGap ||
      oldDelegate.cap != cap ||
      oldDelegate.borderWidth != borderWidth ||
      oldDelegate.borderColor != borderColor;
}

