  /// X-axis label for the nearest data point (tooltip title).
  String? _touchTitle;

  /// Per-series values at the nearest x position (tooltip rows).
  List<BTChartTooltipItem>? _touchItems;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    final effectiveMaxY = widget.maxY ?? _inferMaxY();

    final axisTextStyle = TextStyle(
      fontFamily: BTTypography.fontFamily,
      fontSize: 10.0,
      fontWeight: FontWeight.w500,
      color: colors.text.secondary,
    );

    // Count x ticks from first series spots.
    final xCount = widget.series.isEmpty
        ? 0
        : widget.series.first.spots
                .map((s) => s.x)
                .fold<double>(0, (prev, x) => x > prev ? x : prev)
                .toInt() +
            1;

    final lineBarsData = widget.series.map((s) {
      return LineChartBarData(
        spots: s.spots.map((p) => FlSpot(p.x, p.y)).toList(),
        isCurved: true,
        color: s.color,
        barWidth: 2,
        isStrokeCapRound: true,
        dotData: const FlDotData(show: false),
        belowBarData: BarAreaData(
          show: widget._showArea,
          color: s.color.withOpacity(0.12),
        ),
      );
    }).toList();

    final indicatorLineColor = colors.bg.inverse.withOpacity(0.5);

    final chart = LineChart(
      LineChartData(
        maxY: effectiveMaxY,
        minY: 0,
        lineBarsData: lineBarsData,
        gridData: FlGridData(
          show: true,
          drawVerticalLine: false,
          horizontalInterval: effectiveMaxY / 5,
          getDrawingHorizontalLine: (_) => FlLine(
            color: colors.border.primary,
            strokeWidth: 1,
          ),
        ),
        borderData: FlBorderData(show: false),
        titlesData: FlTitlesData(
          leftTitles: AxisTitles(
            sideTitles: SideTitles(
              showTitles: true,
              reservedSize: 28,
              interval: effectiveMaxY / 5,
              getTitlesWidget: (value, _) => Text(
                value.toInt().toString(),
                style: axisTextStyle,
                textAlign: TextAlign.end,
              ),
            ),
          ),
          bottomTitles: AxisTitles(
            sideTitles: SideTitles(
              showTitles: true,
              reservedSize: 20,
              interval: 1,
              getTitlesWidget: (value, _) {
                if (value != value.truncateToDouble()) {
                  return const SizedBox.shrink();
                }
                final idx = value.toInt();
                if (idx < 0 || idx >= xCount) {
                  return const SizedBox.shrink();
                }
                return Padding(
                  padding: EdgeInsetsDirectional.only(top: 4.0),
                  child: Text('Label', style: axisTextStyle),
                );
              },
            ),
          ),
          rightTitles: const AxisTitles(
            sideTitles: SideTitles(showTitles: false),
          ),
          topTitles: const AxisTitles(
            sideTitles: SideTitles(showTitles: false),
          ),
        ),
        lineTouchData: LineTouchData(
          // true → fl_chart renders dots via getTouchedSpotIndicator.
          handleBuiltInTouches: true,
          touchSpotThreshold: 200,
          // Suppress fl_chart's built-in tooltip balloon — we draw our own.
          touchTooltipData: LineTouchTooltipData(
            getTooltipColor: (_) => Colors.transparent,
            getTooltipItems: (spots) => List.filled(spots.length, null),
          ),
          getTouchedSpotIndicator:
              (LineChartBarData barData, List<int> spotIndexes) {
            return spotIndexes.map((index) {
              return TouchedSpotIndicatorData(
                // Suppress fl_chart's built-in crosshair — we draw our own.
                const FlLine(color: Colors.transparent),
                FlDotData(
                  show: true,
                  getDotPainter: (spot, percent, bar, idx) {
                    return FlDotCirclePainter(
                      radius: 4,
                      color: bar.color ?? Colors.white,
                      strokeWidth: 2,
                      strokeColor: Colors.white,
                    );
                  },
                ),
              );
            }).toList();
          },
          touchCallback: (FlTouchEvent event, LineTouchResponse? response) {
            if (!mounted) return;
            if (!event.isInterestedForInteractions ||
                response == null ||
                response.lineBarSpots == null ||
                response.lineBarSpots!.isEmpty) {
              if (_touchItems != null) {
                setState(() {
                  _touchTitle = null;
                  _touchItems = null;
                });
              }
              return;
            }

            final spots = response.lineBarSpots!;
            final xIdx = spots.first.x.toInt();

            // Title: use spot x index as label
            final newTitle = 'L${xIdx + 1}';

            // Items: one row per series at this x position
            final newItems = spots
                .map((spot) {
                  final seriesIdx = spot.barIndex;
                  final s = (seriesIdx >= 0 &&
                          seriesIdx < widget.series.length)
                      ? widget.series[seriesIdx]
                      : null;
                  return BTChartTooltipItem(
                    color: s?.color ?? Colors.grey,
                    label: s?.label ?? '',
                    value: spot.y.toStringAsFixed(0),
                  );
                })
                .toList();

            if (_touchTitle != newTitle) {
              setState(() {
                _touchTitle = newTitle;
                _touchItems = newItems;
              });
            }
          },
        ),
      ),
    );

    return SizedBox(
      height: widget.height,
      child: LayoutBuilder(
        builder: (context, constraints) {
          final chartWidth = constraints.maxWidth;
          return Stack(
            clipBehavior: Clip.none,
            children: [
              Listener(
                onPointerDown: (e) =>
                    setState(() => _touchPos = e.localPosition),
                onPointerMove: (e) {
                  final pos = e.localPosition;
                  if (pos.dx < 0 ||
                      pos.dx > chartWidth ||
                      pos.dy < 0 ||
                      pos.dy > widget.height) {
                    setState(() {
                      _touchPos = null;
                      _touchTitle = null;
                      _touchItems = null;
                    });
                  } else {
                    setState(() => _touchPos = pos);
                  }
                },
                onPointerUp: (_) => setState(() {
                  _touchPos = null;
                  _touchTitle = null;
                  _touchItems = null;
                }),
                onPointerCancel: (_) => setState(() {
                  _touchPos = null;
                  _touchTitle = null;
                  _touchItems = null;
                }),
                child: chart,
              ),
              // Full-height vertical indicator line.
              if (_touchPos != null)
                Positioned(
                  left: _touchPos!.dx,
                  top: 0,
                  bottom: 20,
                  child: IgnorePointer(
                    child: Container(
                      width: 1,
                      color: indicatorLineColor,
                    ),
                  ),
                ),
              if (_touchPos != null && _touchItems != null)
                BTChartTooltipOverlay(
                  title: _touchTitle,
                  items: _touchItems,
                  touchDx: _touchPos!.dx,
                  touchDy: _touchPos!.dy,
                  chartWidth: chartWidth,
                  chartHeight: widget.height,
                ),
            ],
          );
        },
      ),
    );
  }

  double _inferMaxY() {
    var max = 0.0;
    for (final s in widget.series) {
      for (final p in s.spots) {
        if (p.y > max) max = p.y;
      }
    }
    if (max == 0) return 100;
    return ((max / 20).ceil() * 20).toDouble();
  }
}
